import{_ as a,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const b=JSON.parse('{"title":"96. Rest And Meal Breaks","description":"","frontmatter":{"title":"96. Rest And Meal Breaks","eba":"Mental Health Services 2024-2028","topics":["leave","hours","shift-work","breaks"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/96-rest-and-meal-breaks.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/96-rest-and-meal-breaks.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/96-rest-and-meal-breaks.md"};function o(l,e,i,d,h,m){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_96-rest-and-meal-breaks" tabindex="-1">96. Rest And Meal Breaks <a class="header-anchor" href="#_96-rest-and-meal-breaks" aria-label="Permalink to &quot;96. Rest And Meal Breaks&quot;">​</a></h1><p><strong>96.1</strong> Rest Intervals At a time, suitable to the Employer two rest intervals of 10 minutes each shall be given to all Employees during each day or rostered shift and shall be counted as time worked.</p><p><strong>96.2</strong> Meal breaks Except as provided for in clause 96.2(b) and (c), a meal break of not less than 30 minutes and not more than 60 minutes shall be provided to each Employee during a shift. The meal break shall not be counted as time worked.</p><p><strong>(a)</strong> Employees are entitled to leave the ward/unit area during their meal break.</p><p><strong>(b)</strong> An Employee unable to take their meal break on an ad hoc basis will be paid for the meal break as time worked at their ordinary rate plus 50%.</p><p><strong>(c)</strong> Where Employees are regularly unable to take their meal breaks, a ‘crib time’ arrangement will operate. The crib time arrangement entitles an Employee to a paid meal interval of not less than twenty minutes to commence between three hours and five hours of duty at a rate equivalent to ordinary hours.</p><p><strong>96.3</strong> Meal Break not taken – escalation Each Employer will describe, in writing, the steps to be taken where an Employee does not take a scheduled meal break to ensure that:</p><p><strong>(i)</strong> wherever possible, the meal break is rescheduled and taken during the shift; and</p><p><strong>(ii)</strong> consideration is given to what caused the Employee to miss the scheduled meal break and whether any additional action is required to address those causes to reduce the likelihood.</p><p>Plain language terms: meal break, lunch break, tea break, rest breaks.</p>',10)])])}const c=a(n,[["render",o]]);export{b as __pageData,c as default};
